import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Safety/cloudflare-api-token.md","filePath":"th-TH/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"th-TH/Safety/cloudflare-api-token.md"};function n(c,e,p,s,h,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials ช่วยให้ ImgBed purge Cloudflare CDN cache หลัง files เปลี่ยนแปลง</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>เปิด admin panel แล้วไปที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>ต้องกรอก:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="setting-นี้ทําอะไร" tabindex="-1">Setting นี้ทำอะไร <a class="header-anchor" href="#setting-นี้ทําอะไร" aria-label="Permalink to &quot;Setting นี้ทำอะไร&quot;">​</a></h2><p>Cloudflare อาจ cache public image URLs</p><p>Caching ทำให้เปิด image ได้เร็วขึ้น แต่ก็อาจทำให้ content เก่ายังแสดงอยู่สักพักหลังจาก delete, block, replace หรือ move file</p><p>เมื่อ configure Cloudflare API credentials แล้ว ImgBed จะพยายาม purge Cloudflare cache ที่เกี่ยวข้องหลัง operations เหล่านั้นเสร็จ</p><p>มีประโยชน์เมื่อ:</p><ul><li>คุณ delete image แล้วต้องการให้ public link หยุดใช้งานเร็วที่สุด</li><li>คุณ block image แล้วไม่ต้องการให้ visitors เห็น original file</li><li>คุณ replace file ด้วยชื่อเดิม แล้วต้องการให้ visitors เห็น version ใหม่เร็วขึ้น</li><li>คุณ move หรือ rename files แล้วต้องการ refresh cache ของ old path อย่างรวดเร็ว</li><li>คุณเปลี่ยน public access rules แล้วต้องการให้ public gallery หรือ random image cache update เร็วขึ้น</li></ul><h2 id="ถ้าเว้นว่างจะเกิดอะไร" tabindex="-1">ถ้าเว้นว่างจะเกิดอะไร <a class="header-anchor" href="#ถ้าเว้นว่างจะเกิดอะไร" aria-label="Permalink to &quot;ถ้าเว้นว่างจะเกิดอะไร&quot;">​</a></h2><p>ImgBed ยังทำงานปกติแม้ไม่มี setting นี้</p><p>ข้อแตกต่างคือ ImgBed จะไม่ actively purge Cloudflare CDN cache Visitors อาจยังเห็น content เก่าจนกว่า Cloudflare cache จะ expire เอง</p><h2 id="หา-zone-id-ได้อย่างไร" tabindex="-1">หา Zone ID ได้อย่างไร <a class="header-anchor" href="#หา-zone-id-ได้อย่างไร" aria-label="Permalink to &quot;หา Zone ID ได้อย่างไร&quot;">​</a></h2><p>Zone ID คือ Cloudflare Zone ID ของ site ที่ใช้กับ ImgBed domain ของคุณ</p><ol><li>Sign in เข้า Cloudflare dashboard</li><li>เปิด site ที่มี ImgBed domain</li><li>หา <code>Zone ID</code> ใน site overview page</li><li>Copy ไปใส่ field <code>Zone ID</code> ใน ImgBed</li></ol><p>นี่คือ site Zone ID ไม่ใช่ account ID</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>ใส่ email address ที่ใช้ sign in เข้า Cloudflare</p><p>ต้องตรงกับ API Key ที่ใส่ด้านล่าง</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>ใส่ Cloudflare Global API Key</p><ol><li>Sign in เข้า Cloudflare dashboard</li><li>เปิด profile</li><li>ไปที่ API Tokens page</li><li>หา <code>Global API Key</code></li><li>View แล้ว copy</li><li>Paste ลงใน field <code>API Key</code> ใน ImgBed</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="มีผลเมื่อไร" tabindex="-1">มีผลเมื่อไร <a class="header-anchor" href="#มีผลเมื่อไร" aria-label="Permalink to &quot;มีผลเมื่อไร&quot;">​</a></h2><p>หลังกรอก fields แล้วให้ save settings</p><p>File changes หลังจากนี้จะพยายาม purge Cloudflare cache อัตโนมัติ Operations ที่เกิดก่อนตั้งค่านี้จะไม่ถูก purge ย้อนหลัง ถ้า delete หรือ replace file ก่อนตั้งค่า ให้รอ Cloudflare cache expire หรือ purge เองใน Cloudflare</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="จําเป็นต้องตั้งไหม" tabindex="-1">จำเป็นต้องตั้งไหม? <a class="header-anchor" href="#จําเป็นต้องตั้งไหม" aria-label="Permalink to &quot;จำเป็นต้องตั้งไหม?&quot;">​</a></h3><p>ไม่จำเป็น</p><p>ถ้า domain ไม่ได้ใช้ Cloudflare หรือไม่ติดปัญหา CDN cache delay สามารถเว้นว่างได้</p><h3 id="credentials-ผิดจะทําให้-upload-เสียไหม" tabindex="-1">Credentials ผิดจะทำให้ Upload เสียไหม? <a class="header-anchor" href="#credentials-ผิดจะทําให้-upload-เสียไหม" aria-label="Permalink to &quot;Credentials ผิดจะทำให้ Upload เสียไหม?&quot;">​</a></h3><p>โดยทั่วไปไม่</p><p>Credentials ผิดจะทำให้ ImgBed purge Cloudflare cache ไม่ได้เท่านั้น Upload และ normal file access ควรยังทำงานได้</p><h3 id="ทําไม-deleted-image-ยังเปิดได้" tabindex="-1">ทำไม Deleted Image ยังเปิดได้? <a class="header-anchor" href="#ทําไม-deleted-image-ยังเปิดได้" aria-label="Permalink to &quot;ทำไม Deleted Image ยังเปิดได้?&quot;">​</a></h3><p>สาเหตุที่พบบ่อยที่สุดคือ Cloudflare ยัง cache file เก่าไว้</p><p>เมื่อมี Cloudflare API credentials ที่ถูกต้อง ImgBed จะ purge related URL cache ตอน file ถูก delete</p><h3 id="ทําไม-replace-file-แล้ว-ยังเห็น-image-เก่า" tabindex="-1">ทำไม Replace File แล้ว ยังเห็น Image เก่า? <a class="header-anchor" href="#ทําไม-replace-file-แล้ว-ยังเห็น-image-เก่า" aria-label="Permalink to &quot;ทำไม Replace File แล้ว ยังเห็น Image เก่า?&quot;">​</a></h3><p>โดยปกติก็เกิดจาก CDN cache เช่นกัน</p><p>หลัง configure setting นี้ ImgBed จะพยายาม purge old URL cache เมื่อ file ชื่อเดิมถูก overwrite</p>',44)])])}const b=i(d,[["render",n]]);export{I as __pageData,b as default};
